INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '83a72965-4a62-4e01-be78-f0a14ee39445',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure VNet Segmentation — Subnet Isolation with NSGs, Service Endpoints, and Private DNS$escape$,
  $escape$Azure Virtual Networks use subnets for workload isolation, but NSGs alone leave gaps. Segment workloads into dedicated subnets — snet-app, snet-data, snet-mgmt — and attach NSGs at the subnet level, not the NIC, for cleaner audit trails. NSG rules are stateful and evaluated by ascending priority; always anchor a default-deny at priority 4096.

For PaaS access, Service Endpoints extend your VNet identity to Azure SQL or Storage firewalls — traffic stays on the Microsoft backbone without a public IP route. For stricter isolation, Private Endpoints assign a private IP directly inside your subnet and disable public access entirely. The catch: Private Endpoints require a paired Azure Private DNS Zone (e.g. privatelink.database.windows.net) linked to your VNet. Without it, DNS still resolves the public FQDN and connections silently fail.

In hub-spoke topologies, peer your spoke VNets to the hub and link all Private DNS Zones to the hub. Deploy an Azure Private DNS Resolver in the hub subnet so spoke VMs resolve privatelink records without custom DNS forwarders. Use Azure Firewall Premium in the hub to inspect east-west traffic between spokes via UDRs on each spoke subnet.$escape$,
  $escape$# Create VNet + segmented subnets with NSG and Service Endpoints
az network vnet create \
  --name vnet-prod --resource-group rg-prod \
  --address-prefix 10.0.0.0/16

az network nsg create --name nsg-data --resource-group rg-prod

az network vnet subnet create \
  --name snet-data --vnet-name vnet-prod \
  --resource-group rg-prod \
  --address-prefix 10.0.2.0/24 \
  --network-security-group nsg-data \
  --service-endpoints Microsoft.Sql Microsoft.Storage

# Link Private DNS Zone for Azure SQL Private Endpoint
az network private-dns zone create \
  --resource-group rg-prod \
  --name privatelink.database.windows.net

az network private-dns link vnet create \
  --resource-group rg-prod --zone-name privatelink.database.windows.net \
  --name link-vnet-prod --virtual-network vnet-prod --registration-enabled false$escape$,
