INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '01fd667c-fc3f-47ef-81f0-a6e42ff62b68',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Storage — Object vs Block vs File: Picking the Right Service$escape$,
  $escape$Azure offers three distinct storage primitives, each with a specific use case.

**Blob Storage (object)** — Use Azure Blob Storage for unstructured data: images, videos, backups, ML datasets. Access via REST or `BlobServiceClient`. Tiers (Hot/Cool/Archive) let you trade latency for cost. Enable static website hosting directly from a container.

**Managed Disks (block)** — Attach to Azure VMs as OS or data disks. Choose Premium SSD (P-series) for latency-sensitive workloads like databases, Ultra Disk for sub-millisecond I/O. Block storage is not accessible independently — it lives inside a VM.

**Azure Files (file)** — Fully managed SMB/NFS shares mountable on Windows, Linux, and macOS. Ideal for lift-and-shift apps that expect a file system, or sharing config/state across multiple App Service instances. Supports Azure AD Kerberos auth.

**Decision rule:** Serving assets or storing blobs → Blob Storage. VM disk or database volume → Managed Disk. Shared network drive or legacy app → Azure Files.$escape$,
  $escape$using Azure.Storage.Blobs;

var client = new BlobServiceClient(
    new Uri("https://<account>.blob.core.windows.net"),
    new DefaultAzureCredential());

var container = client.GetBlobContainerClient("assets");
await container.CreateIfNotExistsAsync(
    Azure.Storage.Blobs.Models.PublicAccessType.Blob);

var blob = container.GetBlobClient("logo.png");
await blob.UploadAsync("./logo.png", overwrite: true);

Console.WriteLine($"Uploaded to: {blob.Uri}");$escape$,
  $escape$csharp$escape$,
