INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '600646bf-d9a8-4446-b6d9-f05a1b3fb95f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Database for PostgreSQL Flexible Server — Read Replicas, Backups, and HA Explained$escape$,
  $escape$Azure Database for PostgreSQL Flexible Server is Azure's primary managed relational offering — no VM patching, built-in monitoring, and automated backups to Azure Blob Storage. Configure geo-redundant backups with 1–35 day retention at provision time; point-in-time restore (PITR) lets you fork a new Flexible Server from any second within that window using `az postgres flexible-server restore`.

Read replicas are full Flexible Server instances linked via streaming replication. Unlike RDS, there's no managed reader endpoint — route read traffic at the application layer by referencing the replica's FQDN directly. Replicas don't auto-failover; for automatic failover, use Zone-Redundant HA (`--high-availability ZoneRedundant`), which provisions a synchronous standby in a paired Availability Zone with ~60–120s RTO.

Key operational note: cross-region replicas incur egress costs. Monitor replication lag via `az postgres flexible-server replica list` and inspect the `replicationLag` field. For Azure SQL Managed Instance, read scale-out uses Always On Availability Groups with a built-in listener — a fundamentally different model than Flexible Server's manual routing approach.$escape$,
  $escape$# Create a read replica in a secondary region
az postgres flexible-server replica create \
  --replica-name mydb-replica \
  --resource-group myRG \
  --source-server mydb-primary \
  --location westus2
# Point-in-time restore (forks a new server from any second in retention window)
az postgres flexible-server restore \
  --name mydb-pitr \
  --resource-group myRG \
  --source-server mydb-primary \
  --restore-time "2026-04-16T14:30:00Z"$escape$,
  $escape$bash$escape$,
