INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c4e87923-b845-4243-8eee-16e59d3eacca',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Cost Optimization — Reserved, Spot, On-Demand, and Rightsizing That Actually Saves Money$escape$,
  $escape$Azure pricing has three compute tiers: On-Demand (pay-as-you-go, full price), Reserved Instances (1- or 3-year commitment, up to 72% off), and Spot VMs (up to 90% off, but evictable with 30-second notice). Use Reserved for predictable baseline workloads like App Services or always-on AKS node pools. Use Spot for batch jobs, CI/CD agents, and stateless workers — pair with Azure VMSS eviction policies and terminate handlers. On-Demand is only justified for unpredictable bursts or dev/test.

Rightsizing is where most Azure bills bleed. Use Azure Advisor's cost recommendations to catch over-provisioned VMs — it compares 7-day CPU/memory telemetry against SKU capacity. The `Az.Compute` PowerShell module or `az monitor metrics list` lets you pull this programmatically. Set Budget Alerts in Azure Cost Management with action groups to fire emails or Logic App webhooks at 80%/100% of threshold. Scope budgets to resource groups, not subscriptions, for team-level accountability. Tag resources with `costCenter` and `env` to slice spend in Cost Analysis.$escape$,
  $escape$# Set a budget alert scoped to a resource group
az consumption budget create \
  --budget-name "team-api-monthly" \
  --amount 500 \
  --time-grain Monthly \
  --start-date 2026-04-01 \
  --end-date 2027-04-01 \
  --resource-group myapp-prod-rg \
  --category Cost \
  --thresholds 80 100 \
  --contact-emails ops@example.com \
  --contact-roles Owner Contributor$escape$,
  $escape$bash$escape$,
