INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bd5596d3-9b45-41d9-b955-1e3d44696168',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure High Availability — Multi-Zone Deployments, Failover, and SLA Math$escape$,
  $escape$Azure Availability Zones are physically separate datacenters within a single region, each with independent power, cooling, and networking. Deploying across 2+ zones upgrades your VM SLA from 99.9% (single instance) to 99.99% — a 40x reduction in allowed monthly downtime.

For compute, zone-redundant Azure Load Balancer (Standard SKU) distributes traffic across zones with no extra config. For AKS, pass `--zones 1 2 3` on node pools and pair with `topologySpreadConstraints` in pod specs to enforce spread — AKS alone won't guarantee it.

Storage: swap LRS for ZRS (`Standard_ZRS`) to replicate synchronously across 3 zones with zero RPO on zone failure. Azure SQL Database Business Critical tier places replicas in separate zones by default; General Purpose requires explicit zone-redundancy opt-in via the `zoneRedundant: true` property in Bicep.

Cross-region failover is a separate layer: Azure Front Door for active-active HTTP(S) with health probes, Azure Traffic Manager for DNS-based weighted/priority routing, and Azure Site Recovery for full VM replication to a paired region. Always check the `zones` property on your resource — many SKUs default to zone-pinned, not zone-redundant.$escape$,
  $escape$# Deploy an AKS node pool spread across all 3 availability zones
az aks nodepool add \
  --resource-group myRG \
  --cluster-name myAKS \
  --name prodpool \
  --node-count 3 \
  --zones 1 2 3 \
  --mode System

# Confirm zone assignment on the node pool
az aks nodepool show \
  --resource-group myRG \
  --cluster-name myAKS \
  --name prodpool \
  --query "availabilityZones" -o tsv$escape$,
  $escape$bash$escape$,
