INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '16010079-9f97-499c-bf90-9ee34f45dfca',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Front Door — Cache Setup, Invalidation & Edge Strategy$escape$,
  $escape$Azure Front Door Standard/Premium (AFD) replaces classic Azure CDN and is the right edge layer for any Azure workload. Cache behavior is configured per-route via cache settings on the AFD Route resource — not globally. Set `cacheBehavior` to `Override` and define `cacheDuration` (ISO 8601) to enforce TTL regardless of origin Cache-Control headers. For query strings, use `queryStringCachingBehavior: IgnoreQueryString` for static assets and `UseQueryString` for personalized or filtered API responses. Avoid `BypassCaching` unless the route is purely dynamic.

For cache invalidation, use `az afd endpoint purge` with specific content paths — wildcard purge (`/*`) nukes the entire edge cache globally across all POPs in seconds. Scope purges to changed paths to reduce blast radius. Pair this with versioned asset filenames (e.g., `app.a1b2c3.js`) to make cache busting deterministic and avoid purge dependency for static assets entirely.

Origin response headers like `Surrogate-Control` are stripped by AFD before reaching clients — use `Cache-Control: max-age` on origin for downstream browser caching in addition to AFD TTL.$escape$,
  $escape$# Configure cache override on an AFD route
az afd route update \
  --resource-group myRG \
  --profile-name myAFDProfile \
  --endpoint-name myEndpoint \
  --origin-group myOriginGroup \
  --route-name myRoute \
  --enable-caching true \
  --query-string-caching-behavior IgnoreQueryString \
  --forwarded-protocol HttpsOnly

# Purge specific paths after a deployment
az afd endpoint purge \
  --resource-group myRG \
  --profile-name myAFDProfile \
  --endpoint-name myEndpoint \
  --content-paths /api/config /assets/manifest.json$escape$,
  $escape$bash$escape$,
