INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2859525d-7aa9-4b23-afb2-bfb1c59fb79d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Functions Cold Starts — What Actually Happens and How to Fight Back$escape$,
  $escape$On the Consumption plan, Azure Functions spin down after ~5 minutes of inactivity. The next invocation triggers a cold start: runtime init, package loading, and your app startup code all run before your function handler executes. For .NET isolated workers, this can hit 3–8s. HTTP-triggered functions feel this hardest since users are waiting synchronously.

Mitigations: Use the **Premium plan** with Always Ready instances (minimum 1 pre-warmed instance, no cold start). For Consumption, keep startup code lean — register singletons outside the handler, not inside. Azure's `WEBSITE_RUN_FROM_PACKAGE=1` reduces cold start by mounting a read-only zip rather than extracting files.

Timeout limits matter too: Consumption caps execution at **10 minutes**, Premium/Dedicated at **unlimited** (host.json default is 30 min). Design stateless — never rely on in-memory state between invocations. Use Durable Functions (`IDurableOrchestrationContext`) for stateful workflows; it externalizes state to Azure Storage automatically, surviving restarts and scale-out across multiple instances.$escape$,
  $escape$// host.json — tune timeout and always-ready for Premium plan
{
  "version": "2.0",
  "functionTimeout": "00:30:00",
  "extensions": {
    "http": {
      "routePrefix": "api"
    }
  }
}

// Program.cs — register expensive clients once at startup, not per-invocation
var host = new HostBuilder()
    .ConfigureFunctionsWorkerDefaults()
    .ConfigureServices(services =>
    {
        // Singleton: initialized once per cold start, reused across warm invocations
        services.AddSingleton(_ =>
            new BlobServiceClient(Environment.GetEnvironmentVariable("AzureWebJobsStorage")));
    })
    .Build();

await host.RunAsync();$escape$,
  $escape$csharp$escape$,
