INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '77252966-5cde-4666-9598-29fdbacbdc8e',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Edge Compute vs Cloudflare Workers — What Azure Front Door Actually Gives You$escape$,
  $escape$Azure Front Door Premium spans 192+ PoPs globally and handles TLS termination, anycast routing, and WAF at the edge — but it doesn't execute arbitrary JavaScript like Cloudflare Workers or Vercel Edge Functions. Azure's edge logic lives in the Rules Engine: header rewrites, URL redirects, and geo-based origin selection with zero cold starts. For actual code execution, Azure Static Web Apps links to Azure Functions, but those run regionally, not at CDN PoPs — you still pay a regional round-trip. The real TTFB win on Azure comes from combining Front Door's anycast entry with aggressive Azure CDN caching (Akamai or Verizon tiers), collapsing global TTFB to ~30–60ms. If you need V8 isolate-style edge workers today, the pragmatic pattern is Cloudflare Workers fronting your Azure Container App origin: geo routing and A/B logic happen at CF's edge, while Azure handles stateful compute and data. This hybrid avoids duplicating auth infrastructure while still hitting sub-10ms edge decisions.$escape$,
  $escape$// Cloudflare Worker proxying to Azure Container App
export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const url = new URL(request.url);
    const azureOrigin = "https://my-app.azurecontainerapps.io";

    // Geo-based variant decision at CF edge — no Azure hop needed
    const country = request.cf?.country ?? "US";
    const variant = country === "IN" ? "v2" : "v1";

    url.hostname = new URL(azureOrigin).hostname;
    const proxied = new Request(url.toString(), request);
    proxied.headers.set("X-Edge-Variant", variant);
    proxied.headers.set("X-Forwarded-Country", country);

    return fetch(proxied);
  },
} satisfies ExportedHandler<Env>;$escape$,
  $escape$typescript$escape$,
