INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'db7f084e-0dcd-4b32-8cb2-1a79a55037ce',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Security Hardening — Encryption, Key Vault, WAF, and DDoS in One Stack$escape$,
  $escape$Azure encrypts data at rest by default using platform-managed keys, but production workloads should use Customer-Managed Keys (CMK) in Azure Key Vault with a dedicated HSM-backed tier. For Blob Storage, enable CMK via `Set-AzStorageAccount -KeyvaultEncryption`. In transit, enforce TLS 1.2+ on App Service via `minTlsVersion: '1.2'` in your Bicep/ARM template — never rely on defaults.

Secrets management belongs exclusively in Key Vault. Use managed identity references (`@Microsoft.KeyVault(SecretUri=...)`) in App Service config instead of storing secrets directly — zero credential exposure in env vars or code.

For WAF, deploy Azure Front Door Premium or Application Gateway v2 with WAF Policy in Prevention mode. Attach OWASP 3.2 ruleset and add custom rules to block geo-regions or rate-limit by IP. Front Door gives you global anycast edge enforcement.

DDoS Protection Standard (now Microsoft Defender for DDoS) attaches to a Virtual Network and auto-tunes baselines per public IP. Pair it with Azure Monitor alerts on `DDoSAttackBytesForwarded` to trigger auto-scaling or firewall rule pushes via Logic Apps.$escape$,
  $escape$# Assign CMK to Azure Storage using Key Vault
az storage account update \
  --name mystorageaccount \
  --resource-group myRG \
  --encryption-key-source Microsoft.Keyvault \
  --encryption-key-vault https://mykeyvault.vault.azure.net \
  --encryption-key-name myKey \
  --encryption-key-version "" \
  --identity-type SystemAssigned

# Enforce TLS 1.2 minimum on App Service
az webapp config set \
  --resource-group myRG \
  --name myApp \
  --min-tls-version 1.2$escape$,
  $escape$bash$escape$,
