INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd6220787-2a6e-423f-94f5-e39cca8b36aa',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Region Selection — Latency, Data Residency, and Compliance$escape$,
  $escape$Picking an Azure region isn't just proximity to users — it's a three-way constraint: latency, data residency, and regulatory compliance. Use Azure Speed Test or the `az network watcher` latency report to measure round-trip times before committing. For data residency, Azure Geography boundaries (e.g., "Europe" encompasses North/West Europe) guarantee data never leaves the geo — critical for GDPR. Sovereign clouds (Azure Government, Azure China 21Vianet) are separate endpoints entirely, not just regions. Compliance requirements like PCI-DSS or HIPAA map to specific region capabilities — not every service is available in every region. Use `az account list-locations --query "[].{Name:name, DisplayName:displayName}"` to enumerate, then cross-reference the Azure Products by Region page. For multi-region active-active, pair regions within the same geography (e.g., East US + West US 2) to use Azure Traffic Manager with priority or weighted routing. Availability Zones within a region handle fault isolation; paired regions handle disaster recovery. Always check `az provider show --namespace Microsoft.Sql --query "resourceTypes[].locations"` to confirm your required services exist in the target region before designing your architecture.$escape$,
  $escape$# Check service availability in a specific region before committing
az provider show \
  --namespace Microsoft.Sql \
  --query "resourceTypes[?resourceType=='servers'].locations" \
  --output tsv

# List regions with latency metadata
az network watcher list-available-providers \
  --location eastus \
  --query "countries[].states[].cities[].providers" \
  --output table

# Enumerate all regions in a geography
az account list-locations \
  --query "[?metadata.geographyGroup=='US'].{Name:name,Lat:metadata.latitude,Long:metadata.longitude}" \
  --output table$escape$,
  $escape$bash$escape$,
