INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '11b34d8f-a3e4-46b2-a349-4e91a693d390',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Compliance — SOC 2, GDPR, and HIPAA Without the Guesswork$escape$,
  $escape$Azure ships built-in Policy initiatives for all three frameworks. For HIPAA/HITRUST, assign the initiative ID `a169a624-5599-4385-a696-c8d643089fab` at subscription scope — it maps 300+ controls to your resources automatically. Microsoft Defender for Cloud's Regulatory Compliance dashboard then shows you a live control-by-control posture with remediation steps, no manual gap analysis needed.

For GDPR, enable Diagnostic Settings on every resource and route logs to a Log Analytics Workspace with a 90-day minimum retention. Use Azure Purview to classify sensitive data in Blob Storage and SQL — it detects PII columns automatically and feeds into your Data Subject Request (DSR) workflow.

HIPAA requires a signed BAA with Microsoft (done via the Microsoft Services Agreement portal) and Customer Lockbox enabled so Microsoft engineers can't access your data without explicit approval. Store audit logs in Azure Blob Storage with immutability policies (WORM) — set a time-based retention lock so logs can't be deleted or tampered with, satisfying both SOC 2 CC6.1 and HIPAA §164.312(b).$escape$,
  $escape$# Assign HIPAA/HITRUST built-in initiative to a subscription
az policy assignment create \
  --name "hipaa-hitrust" \
  --display-name "HIPAA HITRUST 9.2" \
  --policy-set-definition "a169a624-5599-4385-a696-c8d643089fab" \
  --scope "/subscriptions/<subscription-id>" \
  --sku standard

# Enable WORM immutability on audit log container
az storage container immutability-policy create \
  --account-name <storage-account> \
  --container-name audit-logs \
  --period 2557$escape$,
  $escape$bash$escape$,
