INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f4b05612-5eae-4b89-8267-557b2cede112',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Deployment Models — Blue/Green Slots, Canary Revisions, and Rolling Updates in AKS$escape$,
  $escape$Azure offers three native deployment patterns tied to specific compute planes. App Service deployment slots are the canonical blue/green tool: deploy to a staging slot, warm it up, then swap with `az webapp deployment slot swap`. The swap is a DNS pointer flip within the same App Service Plan — no cold starts, instant rollback by swapping back. Azure Container Apps uses revision-based traffic splitting for canary: each deploy creates a new revision, and `az containerapp ingress traffic set` lets you shift weights incrementally (e.g., 95/5 → 80/20 → 0/100). Dapr sidecars and scale rules are revision-scoped, so each canary cohort is fully isolated. AKS handles rolling updates natively via `strategy.rollingUpdate`, but tune `maxSurge` and `maxUnavailable` per workload criticality, and pair with `PodDisruptionBudgets` to cap simultaneous evictions. Gate all three with Azure Load Testing on the inactive revision or slot before shifting production weight, and use Application Insights availability tests with Azure Monitor action groups to trigger automated rollbacks on latency or error-rate breaches.$escape$,
  $escape$# Deploy a new Container Apps revision and start a 10% canary split
az containerapp update \
  --name myapp \
  --resource-group myRG \
  --revision-suffix v2 \
  --image myregistry.azurecr.io/myapp:v2

az containerapp ingress traffic set \
  --name myapp \
  --resource-group myRG \
  --revision-weight myapp--v1=90 myapp--v2=10

# Promote to 100% once metrics are clean
az containerapp ingress traffic set \
  --name myapp \
  --resource-group myRG \
  --revision-weight myapp--v2=100$escape$,
  $escape$bash$escape$,
