INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a0a21a46-53d6-4372-ae0c-91b4c1001e8a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Vendor Lock-in — Where Dapr Buys You Portability Without the Tax$escape$,
  $escape$Azure's managed services — Service Bus, Cosmos DB, Azure Functions triggers — offer elite DX but embed portability debt. The real lock-in isn't egress fees; it's cognitive: your team internalizes Azure-specific SDKs, ARM resource models, and Entra IAM patterns that don't transfer anywhere else.

Dapr (Distributed Application Runtime) is the most practical abstraction layer for Azure workloads. Its pub/sub, state store, and secrets building blocks sit atop Azure Service Bus, Cosmos DB, and Azure Key Vault respectively — wired via component YAML files. Swap the YAML, not the application code.

Trade-off: Dapr adds ~2ms sidecar latency per call and requires AKS or Azure Container Apps with sidecar injection enabled. For throughput-critical paths (e.g., >10K msg/s on Service Bus Premium), the native SDK wins by a margin that matters.

For IaC, Terraform beats Bicep on portability. Bicep compiles to ARM — first-class and fast, but Azure-only. Terraform's azurerm provider uses the same HCL as your AWS and GCP modules, letting one platform team own multi-cloud infra without context-switching.

Pick lock-in deliberately: go native where performance and DX justify it, abstract at the seams where migration risk is real.$escape$,
  $escape$// Portable: Dapr pub/sub — swap component YAML to change broker
var client = new DaprClientBuilder().Build();
await client.PublishEventAsync(
    pubsubName: "order-pubsub",   // backed by Azure Service Bus via dapr/components/pubsub.yaml
    topicName: "orders",
    data: new { OrderId = orderId, UserId = userId }
);

// Azure-native: faster, zero abstraction overhead, non-portable
var sender = serviceBusClient.CreateSender("orders");
await sender.SendMessageAsync(
    new ServiceBusMessage(JsonSerializer.Serialize(order))
);$escape$,
  $escape$csharp$escape$,
