INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '949e2104-a33c-40ec-9af2-4245e8c64ead',
  '00000000-0000-0000-0000-000000000001',
  $escape$Azure Cost Anomaly Detection — Catch Spend Spikes Before They Hit Your Budget$escape$,
  $escape$Azure Cost Management's anomaly detection runs daily ML models over your subscription spend and fires alerts when usage deviates from baseline. Enable it via Cost Analysis → Anomaly Alerts or programmatically through the Cost Management REST API. Pair this with Azure Monitor Action Groups to route anomaly notifications to Slack, PagerDuty, or email without polling.

For dashboards, the `Microsoft.CostManagement/query` API lets you pull granular usage data into Azure Managed Grafana or Power BI. Use the `ActualCost` dataset with a `grouping` by `ServiceName` and `ResourceGroupName` to surface which workloads are drifting. Set budget alerts at 80% and 100% thresholds via `Microsoft.Consumption/budgets` — these are distinct from anomaly alerts and fire on absolute spend, not statistical deviation.

For multi-subscription environments, scope queries to a Management Group and use `BillingAccountId` as the grouping key. Export raw usage daily to a Storage Account via Scheduled Exports for long-term trend analysis with Azure Data Explorer or Synapse.$escape$,
  $escape$az costmanagement query \
  --type ActualCost \
  --scope "/subscriptions/{sub-id}" \
  --dataset-aggregation '{"totalCost":{"name":"PreTaxCost","function":"Sum"}}' \
  --dataset-grouping '[{"type":"Dimension","name":"ServiceName"},{"type":"Dimension","name":"ResourceGroupName"}]' \
  --timeframe MonthToDate \
  --query 'properties.rows' \
  --output table$escape$,
  $escape$bash$escape$,
